// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  // Form state
  currentStep: number;
  name: string;
  email: string;
  satisfaction: number;
  selectedFeatures: string[];
  comments: string;
  nameError: string;
  emailError: string;
  onNameChange: (value: string) => void;
  onEmailChange: (value: string) => void;
  onSatisfactionChange: (value: number) => void;
  onFeatureToggle: (feature: string) => void;
  onCommentsChange: (value: string) => void;
  onNext: () => void;
  onBack: () => void;
  onSubmit: () => void;
  isNextDisabled: boolean;
  satisfactionLabels: string[];
  featureOptions: string[];
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [currentStep, setCurrentStep] = useState(0);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState<number>(1);
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  const submit = useAction<ActionSubmitPayload>('submit');

  // Email validation
  const validateEmail = (value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  };

  // Check if current step's required fields are valid
  const isStepValid = useMemo(() => {
    switch (currentStep) {
      case 0: // Step 1: name and email
        return name.trim() !== '' && validateEmail(email);
      case 1: // Step 2: satisfaction
        return satisfaction >= 1 && satisfaction <= 5;
      case 2: // Step 3: features
        return true; // Features step is optional
      case 3: // Step 4: comments
        return true; // Comments are optional
      case 4: // Review step
        return true; // Review is always valid
      default:
        return false;
    }
  }, [currentStep, name, email, satisfaction]);

  const handleNameChange = useCallback((value: string) => {
    setName(value);
    if (nameError) setNameError('');
  }, [nameError]);

  const handleEmailChange = useCallback((value: string) => {
    setEmail(value);
    if (emailError) setEmailError('');
  }, [emailError]);

  const handleSatisfactionChange = useCallback((value: number) => {
    setSatisfaction(value);
  }, []);

  const handleFeatureToggle = useCallback((feature: string) => {
    setSelectedFeatures((prev) =>
      prev.includes(feature)
        ? prev.filter((f) => f !== feature)
        : [...prev, feature]
    );
  }, []);

  const handleCommentsChange = useCallback((value: string) => {
    if (value.length <= 500) {
      setComments(value);
    }
  }, []);

  const handleNext = useCallback(() => {
    // Validate step 1 fields
    if (currentStep === 0) {
      let hasError = false;
      if (name.trim() === '') {
        setNameError('Name is required');
        hasError = true;
      }
      if (!validateEmail(email)) {
        setEmailError('Please enter a valid email address');
        hasError = true;
      }
      if (hasError) return;
    }
    setCurrentStep((prev) => prev + 1);
  }, [currentStep, name, email]);

  const handleBack = useCallback(() => {
    setCurrentStep((prev) => Math.max(0, prev - 1));
  }, []);

  const handleSubmit = useCallback(() => {
    submit({
      name,
      email,
      satisfaction: satisfaction,
      features: selectedFeatures,
      comments,
    });
  }, [name, email, satisfaction, selectedFeatures, comments, submit]);

  return {
    currentStep,
    name,
    email,
    satisfaction,
    selectedFeatures,
    comments,
    nameError,
    emailError,
    onNameChange: handleNameChange,
    onEmailChange: handleEmailChange,
    onSatisfactionChange: handleSatisfactionChange,
    onFeatureToggle: handleFeatureToggle,
    onCommentsChange: handleCommentsChange,
    onNext: handleNext,
    onBack: handleBack,
    onSubmit: handleSubmit,
    isNextDisabled: !isStepValid,
    satisfactionLabels: props.satisfactionLabels,
    featureOptions: props.featureOptions,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  const stepTitles = ['Contact Information', 'Satisfaction Rating', 'Feature Interests', 'Review & Submit'];
  const isReviewStep = props.currentStep === 3;
  const isFirstStep = props.currentStep === 0;
  const isLastStep = props.currentStep === 3;
  const totalSteps = 4;

  const satisfactionOptions = props.satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label: `${index + 1} - ${label}`,
  }));

  const featureCheckboxes = props.featureOptions.map((feature) => ({
    label: feature,
    checked: props.selectedFeatures.includes(feature),
  }));

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* PROGRESS BAR */}
        <Stack gap="var(--ggui-spacing-2)">
          <Progress
            value={props.currentStep}
            max={totalSteps - 1}
            variant="default"
            size="md"
            showLabel={false}
          />
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Step {props.currentStep + 1} of {totalSteps}
          </Text>
        </Stack>

        {/* HEADER */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={2}>{stepTitles[props.currentStep]}</Heading>
        </Stack>

        {/* CONTENT */}
        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Stack gap="var(--ggui-spacing-6)">
            {/* STEP 1: CONTACT INFORMATION */}
            {props.currentStep === 0 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Input
                  label="Name"
                  placeholder="Enter your name"
                  value={props.name}
                  onChange={props.onNameChange}
                  error={props.nameError}
                  required
                />
                <Input
                  label="Email"
                  type="email"
                  placeholder="Enter your email"
                  value={props.email}
                  onChange={props.onEmailChange}
                  error={props.emailError}
                  required
                />
              </Stack>
            )}

            {/* STEP 2: SATISFACTION RATING */}
            {props.currentStep === 1 && (
              <RadioGroup
                label="How satisfied are you?"
                 value={String(props.satisfaction)}
                 onChange={(value: string) => props.onSatisfactionChange(Number(value))}
                options={satisfactionOptions}
                direction="vertical"
              />
            )}

            {/* STEP 3: FEATURE INTERESTS */}
            {props.currentStep === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Text variant="label">Which features interest you?</Text>
                <Stack gap="var(--ggui-spacing-3)">
                  {props.featureOptions.map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={props.selectedFeatures.includes(feature)}
                      onChange={() => props.onFeatureToggle(feature)}
                    />
                  ))}
                </Stack>
              </Stack>
            )}
            {/* STEP 4: COMMENTS */}
            {props.currentStep === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <TextArea
                  label="Additional Comments"
                  placeholder="Share any additional thoughts or feedback (optional)"
                  value={props.comments}
                  onChange={props.onCommentsChange}
                  rows={6}
                  maxLength={500}
                  showCount
                />
              </Stack>
            )}
              {/* STEP 5: REVIEW & SUBMIT */}
              {isReviewStep && (
                <Stack gap="var(--ggui-spacing-6)">
                  <Stack gap="var(--ggui-spacing-4)">
                    <Heading level={4}>Contact Information</Heading>
                    <Stack gap="var(--ggui-spacing-2)">
                      <Row align="center" justify="between">
                        <Text variant="label">Name:</Text>
                        <Text>{props.name}</Text>
                      </Row>
                      <Row align="center" justify="between">
                        <Text variant="label">Email:</Text>
                        <Text>{props.email}</Text>
                      </Row>
                    </Stack>
                  </Stack>

                  <Divider />

                  <Stack gap="var(--ggui-spacing-4)">
                    <Heading level={4}>Satisfaction Rating</Heading>
                    <Text>
                      {props.satisfaction > 0
                        ? `${props.satisfaction} - ${props.satisfactionLabels[props.satisfaction - 1]}`
                        : 'Not provided'}
                    </Text>
                  </Stack>

                  <Divider />

                  <Stack gap="var(--ggui-spacing-4)">
                    <Heading level={4}>Feature Interests</Heading>
                    {props.selectedFeatures.length > 0 ? (
                      <Stack gap="var(--ggui-spacing-2)">
                        {props.selectedFeatures.map((feature) => (
                          <Badge key={feature} variant="primary">
                            {feature}
                          </Badge>
                        ))}
                      </Stack>
                    ) : (
                      <Text color="var(--ggui-color-onSurfaceVariant)">No features selected</Text>
                    )}
                  </Stack>

                  <Divider />

                  <Stack gap="var(--ggui-spacing-4)">
                    <Heading level={4}>Additional Comments</Heading>
                    <Text>
                      {props.comments || '(No comments provided)'}
                    </Text>
                  </Stack>
                </Stack>
              )}
          </Stack>
        </Card>

        {/* FOOTER / ACTIONS */}
        <Row gap="var(--ggui-spacing-4)" align="center" justify="between">
          {!isFirstStep && (
            <Button
              variant="ghost"
              onClick={props.onBack}
            >
              Back
            </Button>
          )}
          {!isLastStep ? (
            <Button
              variant="primary"
              onClick={props.onNext}
              disabled={props.isNextDisabled}
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={props.onSubmit}
            >
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}

