// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string; title?: string; priority?: string; assignee?: string; dueDate?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  // Board state & data
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  columns: Array<{ id?: string; name?: string }>;
  totalTasks: number;
  completedTasks: number;

  // Handlers
  onTaskMove: (taskId: string, targetColumn: string) => void;
  onTaskEdit: (taskId: string, newTitle: string) => void;
  onTaskCreate: (title: string, priority: 'low' | 'medium' | 'high', assignee?: string, dueDate?: string) => void;

  // UI state
  editingTaskId: string | null;
  setEditingTaskId: (id: string | null) => void;
  expandedAddTaskColumn: string | null;
  setExpandedAddTaskColumn: (id: string | null) => void;
  newTaskTitle: string;
  setNewTaskTitle: (title: string) => void;
  newTaskPriority: 'low' | 'medium' | 'high';
  setNewTaskPriority: (priority: 'low' | 'medium' | 'high') => void;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  // Merge initial tasks with streamed updates
  const [allTasks, setAllTasks] = useState(props.tasks);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [expandedAddTaskColumn, setExpandedAddTaskColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // DO NOT EDIT wire hooks below — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Update board when stream events arrive
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'delete' && task?.id) {
        setAllTasks(prev => prev.filter(t => t.id !== task.id));
      } else if (action === 'create' && task?.id) {
        setAllTasks(prev => [...prev, task]);
      } else if (action === 'edit' || action === 'move') {
        setAllTasks(prev => prev.map(t => t.id === task?.id ? { ...t, ...task } : t));
      }
    }
  }, [taskChanged.latest]);

  // Compute summary stats
  const totalTasks = allTasks.length;
  const completedTasks = allTasks.filter(t => t.column === 'done').length;

  // Handlers
  const handleTaskMove = useCallback((taskId: string, targetColumn: string) => {
    taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
    setAllTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: targetColumn } : t));
  }, [taskUpdate]);

  const handleTaskEdit = useCallback((taskId: string, newTitle: string) => {
    const task = allTasks.find(t => t.id === taskId);
    taskUpdate({ action: 'edit', taskId, data: { column: task?.column || 'todo', title: newTitle } });
    setAllTasks(prev => prev.map(t => t.id === taskId ? { ...t, title: newTitle } : t));
    setEditingTaskId(null);
  }, [taskUpdate, allTasks]);

  const handleTaskCreate = useCallback((title: string, priority: 'low' | 'medium' | 'high', assignee?: string, dueDate?: string) => {
    const newTaskId = `task-${Date.now()}`;
    const newTask = { id: newTaskId, title, priority, column: 'todo', assignee, dueDate };
    taskUpdate({ action: 'create', taskId: newTaskId, data: { column: 'todo', title, priority, assignee, dueDate } });
    setAllTasks(prev => [...prev, newTask]);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setExpandedAddTaskColumn(null);
  }, [taskUpdate]);

  return {
    tasks: allTasks,
    columns: props.columns,
    totalTasks,
    completedTasks,
    onTaskMove: handleTaskMove,
    onTaskEdit: handleTaskEdit,
    onTaskCreate: handleTaskCreate,
    editingTaskId,
    setEditingTaskId,
    expandedAddTaskColumn,
    setExpandedAddTaskColumn,
    newTaskTitle,
    setNewTaskTitle,
    newTaskPriority,
    setNewTaskPriority,
  };
}

