  onEditStart: () => void;
  onEditSave: (newTitle: string) => void;
  onEditCancel: () => void;
  onMove: (targetColumn: string) => void;
  onDoubleClick?: () => void;
}

function TaskCard({ task, priorityColors, columns, isEditing, onEditStart, onEditSave, onEditCancel, onMove, onDoubleClick }: TaskCardProps) {
  const [editTitle, setEditTitle] = useState(task.title || '');
  const [originalTitle, setOriginalTitle] = useState(task.title || '');

  useEffect(() => {
    setEditTitle(task.title || '');
    setOriginalTitle(task.title || '');
  }, [task.title, isEditing]);

  const priorityColor = priorityColors[task.priority || 'medium'];
  const otherColumns = columns.filter(c => c.id !== task.column);

  const handleSave = () => {
    if (editTitle.trim()) {
      onEditSave(editTitle);
    }
  };

  const handleCancel = () => {
    setEditTitle(originalTitle);
    onEditCancel();
  };

  return (
    <Card shadow="sm" padding="var(--ggui-spacing-3)" radius="md">
      <Stack gap="var(--ggui-spacing-2)">
        {isEditing ? (
          <Stack gap="var(--ggui-spacing-2)">
            <Input
              label="Task title"
              value={editTitle}
              onChange={setEditTitle}
              size="sm"
            />
            <Row gap="var(--ggui-spacing-2)" justify="end">
              <Button variant="ghost" size="sm" onClick={handleCancel}>Cancel</Button>
              <Button variant="primary" size="sm" onClick={handleSave}>Save</Button>
            </Row>
          </Stack>
        ) : (
          <>
            <Text
              is="span"
              weight="semibold"
              as={Clickable}
              onClick={onEditStart}
              onDoubleClick={onDoubleClick}
              style={{ cursor: 'pointer' }}
            >
              {task.title || 'Untitled'}
            </Text>
            <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
              <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                <Badge
                  size="sm"
                  variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'success'}
                >
                  {task.priority || 'medium'}
                </Badge>
                {task.assignee && <Avatar name={task.assignee} size="sm" shape="circle" />}
                {task.dueDate && (
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
