  const ratingStars = props.product.rating ? Math.round(props.product.rating) : 0;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* TOP SECTION: Image, Title, Price, Rating, Stock */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-6)" align="start" wrap>
          {/* Product Image Placeholder */}
          <Box
            padding="var(--ggui-spacing-8)"
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
            style={{ minWidth: '300px', minHeight: '300px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
              <Icon name="image" size={48} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                {props.product.name || 'Product Image'}
              </Text>
            </Stack>
          </Box>

          {/* Details Section */}
          <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1 }}>
            {/* Title */}
            <Heading level={1}>{props.product.name || 'Product'}</Heading>

            {/* Price */}
            <Heading level={3} color="var(--ggui-color-primary-600, #0284c7)">
              {props.product.currency || '$'}{props.product.price?.toFixed(2) || '0.00'}
            </Heading>

            {/* Rating Stars */}
            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
              <Stack direction="horizontal" gap={0}>
                {[1, 2, 3, 4, 5].map((star) => (
                  <Icon
                    key={star}
                    name={star <= ratingStars ? 'star' : 'star'}
                    size={16}
                    color={star <= ratingStars ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outline, #d4d4d8)'}
                  />
                ))}
              </Stack>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {props.product.rating?.toFixed(1) || '0.0'} ({props.product.reviewCount || 0} reviews)
              </Text>
            </Stack>

            {/* Stock Status Badge */}
            <Badge
              variant={isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success'}
              size="md"
            >
              {isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock'}
            </Badge>
          </Stack>
        </Stack>

        <Divider />

        {/* MIDDLE SECTION: Tabs */}
        <Tabs
          variant="line"
          items={[
            {
              key: 'description',
              label: 'Description',
              content: (
                <Card padding="var(--ggui-spacing-4)" shadow="none" border={false}>
                  <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                    {props.product.description || 'No description available.'}
                  </Text>
                </Card>
              ),
            },
            {
              key: 'specifications',
              label: 'Specifications',
              content: (
                <Card padding="var(--ggui-spacing-4)" shadow="none" border={false}>
                  {Array.isArray(props.product.specifications) && props.product.specifications.length > 0 ? (
                    <Stack gap="var(--ggui-spacing-3)">
                      {props.product.specifications.map((spec: Record<string, unknown>, idx: number) => (
                        <Stack key={idx} direction="horizontal" gap="var(--ggui-spacing-2)" justify="between">
                          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">{String(Object.keys(spec)[0])}</Text>
                          <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">{String(Object.values(spec)[0])}</Text>
                        </Stack>
                      ))}
                    </Stack>
                  ) : (
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      No specifications available.
                    </Text>
                    </Text>
                  )}
                </Card>
              ),
            },
            {
              key: 'reviews',
              label: 'Reviews',
              content: (
                <Card padding="var(--ggui-spacing-4)" shadow="none" border={false}>
                  {Array.isArray(props.product.reviews) && props.product.reviews.length > 0 ? (
                    <Stack gap="var(--ggui-spacing-4)">
                      {props.product.reviews.map((review: Record<string, unknown>, idx: number) => (
                        <Card key={idx} padding="var(--ggui-spacing-3)" shadow="sm" border>
                          <Stack gap="var(--ggui-spacing-2)">
                            <Stack direction="horizontal" justify="between" align="center">
                              <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                                {String(review.author) || 'Anonymous'}
                              </Text>
                              <Stack direction="horizontal" gap={0}>
                                {[1, 2, 3, 4, 5].map((star) => (
                                  <Icon
                                    key={star}
                                    name="star"
                                    size={14}
                                    color={star <= (Number(review.rating) || 0) ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outline, #d4d4d8)'}
                                  />
                                ))}
                              </Stack>
                            </Stack>
                            <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                              {String(review.text) || 'No review text provided.'}
                            </Text>
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                              {review.date ? new Date(String(review.date)).toLocaleDateString() : 'Date not provided'}
                            </Text>
                          </Stack>
                        </Card>
                      ))}
                    </Stack>
                  ) : (
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      No reviews yet.
                    </Text>
                  )}
                </Card>
              ),
            },
          ]}
          activeKey={props.activeTab}
          onChange={props.onTabChange}
        />

        <Divider />

        {/* BOTTOM SECTION: Quantity Selector and Add to Cart */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="center" justify="between">
          <Stack direction="horizontal" gap="var(--ggui-spacing-3)" align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Quantity:
            </Text>
            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
              <Button
                variant="outline"
                size="sm"
                onClick={() => props.onQuantityChange(props.quantity - 1)}
                disabled={props.quantity <= 1 || isOutOfStock}
              >
                −
              </Button>
              <Text variant="label" align="center" style={{ minWidth: '40px' }}>
                {props.quantity}
              </Text>
              <Button
                variant="outline"
                size="sm"
                onClick={() => props.onQuantityChange(props.quantity + 1)}
                disabled={props.quantity >= (props.product.stock ?? 0) || isOutOfStock}
              >
                +
              </Button>
            </Stack>
          </Stack>

          <Button
            variant="primary"
            size="lg"
            onClick={props.onAddToCart}
            disabled={isOutOfStock}
          >
            Add to Cart
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

