type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  // Header
  title: string;
  currentUser: string;
  participantCount: number;
  typingUser: string | null;

  // Messages
  allMessages: Array<{ sender?: string; text?: string; timestamp?: string }>;

  // Input
  inputValue: string;
  onInputChange: (value: string) => void;
  onSendMessage: () => void;
  isSendDisabled: boolean;

  // Scroll ref for auto-scroll
  messagesEndRef: React.RefObject<HTMLDivElement>;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [inputValue, setInputValue] = useState('');
  const [allMessages, setAllMessages] = useState(props.messages);
  const [typingUser, setTypingUser] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Wire hooks
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage');
  const message = useStream<StreamMessage>('message');
  const typing = useStream<StreamTyping>('typing');

  // Append new messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Update typing indicator
  useEffect(() => {
    if (typing.latest) {
      if (typing.latest.active) {
        setTypingUser(typing.latest.sender || null);
      } else if (typing.latest.sender === typingUser) {
        setTypingUser(null);
      }
    }
  }, [typing.latest]);

  // Auto-scroll to bottom on new messages
  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [allMessages]);

  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      sendMessage({
        text: inputValue,
        timestamp: new Date().toISOString(),
      });
      setInputValue('');
    }
  }, [inputValue, sendMessage]);

  return {
    title: props.title || 'Chat',
    currentUser: props.currentUser,
    participantCount: props.participantCount,
    typingUser,
    allMessages,
    inputValue,
    onInputChange: setInputValue,
    onSendMessage: handleSendMessage,
    isSendDisabled: !inputValue.trim(),
    messagesEndRef,
  };
}
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      props.onSendMessage();
    }
  };

  const formatTimestamp = (ts?: string): string => {
    if (!ts) return '';
    try {
      return new Date(ts).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  // Group consecutive messages by sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; messages: typeof props.allMessages }> = [];
    let currentGroup: typeof props.allMessages | null = null;
    let currentSender: string | undefined;

    props.allMessages.forEach((msg) => {
      if (msg.sender === currentSender) {
        currentGroup?.push(msg);
      } else {
        if (currentGroup) {
          groups.push({ sender: currentSender, messages: currentGroup });
        }
        currentSender = msg.sender;
        currentGroup = [msg];
      }
    });

    if (currentGroup) {
      groups.push({ sender: currentSender, messages: currentGroup });
    }

    return groups;
  }, [props.allMessages]);

  return (
    <Container maxWidth='2xl' padding='var(--ggui-spacing-6)'>
      <Card shadow='md' radius='lg' padding='var(--ggui-spacing-6)' style={{ display: 'flex', flexDirection: 'column', height: '100vh', maxHeight: '80vh' }}>
        <Stack gap='var(--ggui-spacing-4)' style={{ flex: '0 0 auto' }}>
          {/* HEADER */}
          <Stack direction='horizontal' justify='between' align='center'>
            <Stack direction='horizontal' gap='var(--ggui-spacing-3)' align='center'>
              <Heading level={2}>{props.title || 'Chat'}</Heading>
              <Badge variant='primary' size='sm'>{props.participantCount || 0}</Badge>
          </Stack>

          {/* TYPING INDICATOR */}
          {props.typingUser && (
            <Stack direction='horizontal' gap='var(--ggui-spacing-2)' align='center'>
              <Text variant='caption' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
                {props.typingUser} is typing
              </Text>
              <Spinner size={16} color='var(--ggui-color-primary-600, #0284c7)' />
            </Stack>
          )}
        </Stack>

        {/* MESSAGE LIST */}
        <Stack
          gap='var(--ggui-spacing-4)'
          style={{
            flex: '1 1 auto',
            overflowY: 'auto',
            paddingTop: 'var(--ggui-spacing-4)',
            paddingBottom: 'var(--ggui-spacing-4)',
          }}
        >
          {groupedMessages.length === 0 ? (
            <Stack align='center' justify='center' style={{ flex: 1 }}>
              <Text variant='bodySmall' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
                No messages yet
              </Text>
            </Stack>
          ) : (
            groupedMessages.map((group, groupIdx) => {
              const isCurrentUser = group.sender === props.currentUser;
              return (
                <Stack
                  key={`group-${groupIdx}`}
                  gap='var(--ggui-spacing-2)'
                  align={isCurrentUser ? 'end' : 'start'}
                  style={{ maxWidth: '70%', alignSelf: isCurrentUser ? 'flex-end' : 'flex-start' }}
                >
                  {group.messages.map((msg, idx) => (
                    <Box
                      key={`msg-${groupIdx}-${idx}`}
                      padding='var(--ggui-spacing-3)'
                      borderRadius='var(--ggui-shape-radius-lg, 12px)'
                      background={
                        isCurrentUser
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                      }
                    >
                      <Stack gap='var(--ggui-spacing-1)'>
                        {group.sender && (
                          <Text
                            variant='label'
                            color={
                              isCurrentUser
                                ? '#ffffff'
                                : 'var(--ggui-color-onSurface, #18181b)'
                            }
                          >
                            {group.sender}
                          </Text>
                        )}
                        <Text
                          variant='body'
                          color={
                            isCurrentUser
                              ? '#ffffff'
                              : 'var(--ggui-color-onSurface, #18181b)'
                          }
                        >
                          {msg.text}
                        </Text>
                        {msg.timestamp && (
                          <Text
                            variant='caption'
                            color={
                              isCurrentUser
                                ? 'rgba(255, 255, 255, 0.7)'
                                : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                            }
                          >
                            {formatTimestamp(msg.timestamp)}
                          </Text>
                        )}
                      </Stack>
                    </Box>
                  ))}
                </Stack>
              );
            })
          )}
          <div ref={props.messagesEndRef} />
        </Stack>

        {/* INPUT AREA */}
        <Stack gap='var(--ggui-spacing-3)' style={{ flex: '0 0 auto' }}>
          <Row gap='var(--ggui-spacing-3)' align='end'>
            <TextArea
              label='Message'
              value={props.inputValue}
              onChange={props.onInputChange}
              onKeyDown={handleKeyDown}
              placeholder='Type a message...'
              rows={2}
              style={{ flex: 1 }}
            />
            <Button
              variant='primary'
              onClick={props.onSendMessage}
              disabled={props.isSendDisabled}
            >
              Send
            </Button>
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

