type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  lastUpdated: string;
  priceUpdates: StreamPriceUpdate[];
  highlightedStocks: Set<string>;
  marketStatus: StreamMarketStatus | null;
  loading: boolean;
  error: string | null;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState(new Date().toLocaleTimeString());
  const [highlightedStocks, setHighlightedStocks] = useState<Set<string>>(new Set());
  const [loading, setLoading] = useState(!props.stocks || props.stocks.length === 0);
  const [error, setError] = useState<string | null>(null);
  const highlightTimeoutRef = useRef<Record<string, NodeJS.Timeout>>({});

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // Update loading state when stocks arrive
  useEffect(() => {
    if (props.stocks && props.stocks.length > 0) {
      setLoading(false);
    }
  }, [props.stocks]);

  // Real-time clock for continuous timestamp updates
  useEffect(() => {
    const timer = setInterval(() => {
      setLastUpdated(new Date().toLocaleTimeString());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  // Merge incoming price updates into stocks array
  useEffect(() => {
    if (priceUpdate.latest) {
      setStocks((prev) => {
        const updated = prev.map((stock) =>
          stock.symbol === priceUpdate.latest?.symbol
            ? {
                ...stock,
                price: priceUpdate.latest.price ?? stock.price,
                change: priceUpdate.latest.change ?? stock.change,
                changePercent: priceUpdate.latest.changePercent ?? stock.changePercent,
              }
            : stock
        );
        return updated;
      });

      // Trigger highlight animation
      const symbol = priceUpdate.latest.symbol;
      if (symbol) {
        if (highlightTimeoutRef.current[symbol]) {
          clearTimeout(highlightTimeoutRef.current[symbol]);
        }
        setHighlightedStocks((prev) => new Set([...prev, symbol]));
        highlightTimeoutRef.current[symbol] = setTimeout(() => {
          setHighlightedStocks((prev) => {
            const next = new Set(prev);
            next.delete(symbol);
            return next;
          });
          delete highlightTimeoutRef.current[symbol];
        }, 600);
      }
    }
  }, [priceUpdate.latest]);

  return {
    stocks,
    lastUpdated,
    priceUpdates: priceUpdate.all || [],
    highlightedStocks,
    marketStatus: marketStatus.latest || null,
    loading,
    error,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function StockCard({
  stock,
  isHighlighted,
}: {
  stock: { symbol?: string; name?: string; price?: number; change?: number; changePercent?: number };
  isHighlighted: boolean;
}) {
  const isPositive = (stock.change ?? 0) >= 0;
  const changeColor = isPositive ? 'var(--ggui-color-success-500, #22c55e)' : 'var(--ggui-color-error-500, #ef4444)';
  const changeBorderColor = isPositive ? 'var(--ggui-color-success-100, #dcfce7)' : 'var(--ggui-color-error-100, #fee2e2)';
  return (
    <Card
      shadow="md"
      padding="var(--ggui-spacing-4, 16px)"
      radius="lg"
      border={true}
      style={{
        borderColor: isHighlighted ? changeColor : 'var(--ggui-color-outlineVariant, #e4e4e7)',
        background: isHighlighted ? changeBorderColor : 'var(--ggui-color-surface, #ffffff)',
        transition: 'all 300ms ease-in-out',
        animation: isHighlighted ? `keyframes-flash 600ms ease-in-out` : 'none',
      }}
    >
      <Stack gap="var(--ggui-spacing-2, 8px)">
        {/* TICKER SYMBOL - LARGE AND BOLD */}
        <Text variant="overline" size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
          {stock.symbol || 'N/A'}
        </Text>
        {/* COMPANY NAME */}
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {stock.name || 'Unknown'}
        </Text>
        {/* CURRENT PRICE */}
        <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
          ${(stock.price ?? 0).toFixed(2)}
        </Text>
        {/* CHANGE AMOUNT AND PERCENTAGE WITH ARROW */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-1, 4px)" align="center">
          <Icon
            name={isPositive ? 'arrow-up' : 'arrow-down'}
            size={16}
            color={changeColor}
          />
          <Text size="sm" weight="medium" color={changeColor}>
            {isPositive ? '+' : ''}{(stock.change ?? 0).toFixed(2)} ({(stock.changePercent ?? 0).toFixed(2)}%)
          </Text>
        </Stack>
      </Stack>
    </Card>
  );
}

function ComponentView(props: ViewProps) {
  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-4, 16px)">
        {/* HEADER WITH TITLE AND TIMESTAMP */}
        <Stack gap="var(--ggui-spacing-2, 8px)" direction="horizontal" justify="between" align="center">
          <Stack gap="var(--ggui-spacing-2, 8px)">
            <Heading level={1}>Market Watch</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
