          )}
        </Stack>

        {/* ERROR STATE */}
        {props.error && <Alert variant="error" title="Error">{props.error}</Alert>}

        {/* LOADING STATE */}
        {props.loading ? (
          <Box style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '200px' }}>
