// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  // Current step (1, 2, or 3)
  step: 1 | 2 | 3;
  // Progress percentage for progress bar (0-100)
  progress: number;

  // Step 1 - Profile Setup state
  name: string;
  email: string;
  selectedAvatar: string;
  avatarOptions: string[];

  // Step 2 - Preferences state
  role: string;
  emailNotifications: boolean;
  theme: 'light' | 'dark';
  roleOptions: string[];

  // Validation errors
  nameError: string;
  emailError: string;

  // Handlers for step 1
  onNameChange: (value: string) => void;
  onEmailChange: (value: string) => void;
  onAvatarSelect: (avatar: string) => void;

  // Handlers for step 2
  onRoleChange: (role: string) => void;
  onEmailNotificationsChange: (enabled: boolean) => void;
  onThemeChange: (theme: 'light' | 'dark') => void;

  // Navigation handlers
  onNext: () => void;
  onBack: () => void;
  onComplete: () => void;

  // State getters for validation
  isStep1Valid: boolean;
  isStep2Valid: boolean;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [step, setStep] = useState<1 | 2 | 3>(1);
  const [name, setName] = useState(props.initialProfile?.name || '');
  const [email, setEmail] = useState(props.initialProfile?.email || '');
  const [selectedAvatar, setSelectedAvatar] = useState(props.initialProfile?.avatar || props.avatarOptions[0] || '');
  const [role, setRole] = useState(props.initialProfile?.role || props.roleOptions[0] || '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile?.emailNotifications !== false);
  const [theme, setTheme] = useState<'light' | 'dark'>(props.initialProfile?.theme === 'dark' ? 'dark' : 'light');

  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const nameError = !name.trim() && step > 1 ? 'Name is required' : '';
  const emailError = !validateEmail(email) && step > 1 ? 'Please enter a valid email address' : '';

  const isStep1Valid = name.trim().length > 0 && validateEmail(email);
  const isStep2Valid = true;

  const progress = ((step - 1) / 2) * 100;

  const handleNext = useCallback(() => {
    if (step === 1 && !isStep1Valid) return;
    if (step < 3) setStep((s) => (s + 1) as 1 | 2 | 3);
  }, [step, isStep1Valid]);

  const handleBack = useCallback(() => {
    if (step > 1) setStep((s) => (s - 1) as 1 | 2 | 3);
  }, [step]);

  const handleComplete = useCallback(() => {
    if (isStep1Valid && isStep2Valid) {
      complete({
        name,
        email,
        avatar: selectedAvatar,
        role,
        emailNotifications,
        theme,
      });
    }
  }, [name, email, selectedAvatar, role, emailNotifications, theme, isStep1Valid, isStep2Valid, complete]);

  return {
    step,
    progress,
    name,
    email,
    selectedAvatar,
    avatarOptions: props.avatarOptions,
    role,
    emailNotifications,
    theme,
    roleOptions: props.roleOptions,
    nameError,
    emailError,
    onNameChange: setName,
    onEmailChange: setEmail,
    onAvatarSelect: setSelectedAvatar,
    onRoleChange: setRole,
    onEmailNotificationsChange: setEmailNotifications,
    onThemeChange: setTheme,
    onNext: handleNext,
    onBack: handleBack,
    onComplete: handleComplete,
    isStep1Valid,
    isStep2Valid,
  };
}
}

